import{select as d3Select}from"d3-selection";import{hsl as d3Hsl}from"d3-color";import{color}from"../utils.mjs";export default function Text(t){const l=t.meta.xScale,c=t.meta.yScale;return function(t){t.each(function(t){t.sampler="builtIn",t.fnType="vector";const e=d3Select(this).selectAll(":scope > text.fn-text").data([t.location]);var r=e.enter().append("text").attr("class","fn-text fn-text-"+t.index);const o=color(t,t.index),a=e.merge(r).attr("fill",d3Hsl(o.toString()).brighter(1.5).formatHex()).attr("x",t=>l(t[0])).attr("y",t=>c(t[1])).text(()=>t.text);if(t.attr)for(const n in t.attr)a.attr(n,t.attr[n]);e.exit().remove()})}}